(1240, 87, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '한국의 경제는 수출 중심입니다. 1980년대 이전에는 단수한 조립 \r\n제품을수출했습니다. 하지만 1990년대 이후 자동차롸 기계 등을 \r\n수출했고 2000년대 대부부터는 휴대전화나 컴퓨터와 같은 전자재품의\r\n수출이 많이 늘었습니다. 한국제품은 주로 중국과 미국으로 수출되고 \r\n있습니다.', '', NULL, NULL, 'B', '1980년대에는 수출을 하지 않았습니다.\r', '', NULL, NULL, '1990년대부터 조립 제품을 수출했습니다.', '', NULL, NULL, '2000년대의 대표적인 수출품은 잔자제품입니다.', '', NULL, NULL, ' 현재 한국이 수출을 가장 적게 하는 나라는 미국입니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"b