(1282, 88, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '칸 씨는 공장에 다닌 지 1년쯤 되었습니다. 제가 우리 공장에 처음 \r\n 들어왔을 때 칸 씨가 저를 많이 도와줘서 늘 고맙게 생각하고 있습니다.\r\n 칸 씨는 활발 하고 이야기도 잘해서 회사 사람들에게 인기가 많습니다.\r\n 칸 씨는 최고의 기술자가 되어 고향에 돌어갈 거라고 했습니다.', '', NULL, NULL, 'A', '동료들은 칸 씨의 활발한 성격을 좋아합니다.', '', NULL, NULL, '칸 씨는 이 사람에게 많은 도움을 받았습니다.\r', '', NULL, NULL, '칸 씨는 꿈은 한국에서 기술자로 일하는 것입니다.\r', '', NULL, NULL, '이 사람은 칸 씨보다 먼저 공장에 다니기 시작했습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bol