(1323, 89, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '제 이름은 자야입니다. 제가 일하는 벽돌 공장에서는 점심시간에 가끔 한잔할 때가 있습니다. 그럴 때 한국 사람들 중에는 서서 술을 마시는 사람도 있습니다. 그러나 몽골 사람들은 술을 마실 때 서서 마시지 않고 앉아서 마셔야 합니다. 그리고 음식을 먹을 때에도 앉아서 먹어야 합니다. 특히 다른 사람의 집에 갈 때 서서 술을 마시거나음식을 먹는 것은 몽골의 예의에 맞지 않습니다.', '', NULL, NULL, 'B', '몽골에는 술을 서서 마셔야 합니다.', '', NULL, NULL, '몽골에는 술을 앉아서 마셔야 합니다.', '', NULL, NULL, '몽골에는 술을 왼손으로 마셔야 합니다.\r', '', NULL, NULL, '몽골에는 술을 음식과 함께 마셔야 합니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"under