(1399, 91, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.\r\n', '요즘 날씨가 좀 더워져서 일할 때 땀이 많이 납니다. 오늘 \r\n집에 가서 제일 먼저__________합니다.', '', NULL, NULL, 'D', '청소하려고                                                        ', '', NULL, NULL, ' 정리하려고', '', NULL, NULL, '요리하려고                                                        ', '', NULL, NULL, '샤워하려고', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1400, 91, '다음 설명에 알맞은 어휘를 고르십시오.', '노후 생활을 보장하기 위해 정부가 운영하는 사회보장제도입니다. \r\n일정한 나이가 되거나 장애를 입으면 연금을 받을 수 있으며, 유족\r\n에게도 혜택이 제공됩니다.', '', NULL, NULL, 'C', '산재 보험                                                                     ', '', NULL, NULL, '상해 보험', '', NULL, NULL, '국민연금                                                                      ', '', NULL, NULL, '건강 보험', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]'),
(1401, 91, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '한국의 전통 문화를 알고 싶으면 박불관이나 고궁에 가는 것도 \r\n좋지만 민속촌에 가 보는 것도 좋습니다. 민속촌에 가면 한국의\r\n전통 문화를 좀 더 가까이에서 만날 수 있습니다. 한국의 옛날 옷\r\n을 구경할 수 있습니다. 또 한국의 전통 혼례와 전통 음악 공연도           불 수 있습니다. 널뛰기나 윳놀이 같은 한국의 전통  놀이도 직접 \r\n해 볼 수 있으면, 파전이나 동동주 같은 한국의 전통 음식도 맛볼\r\n수 있습니다.', '', NULL, NULL, 'D', '민속촌 무료 개방 안내                         ', '', NULL, NULL, '민속촌의 이용 요금 안내\r', '', NULL, NULL, '민속촌 관람 시간 안내                         ', '', NULL, NULL, '민속촌의 문화 체험 안내', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\