(1441, 92, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '한국 전자 직원 여러분! 휴게실은 금연 구역입니다. 휴게실에서\r\n 담배를 피우면 안 됩니다. 또한 휴게실은 금주 구역이니까 술을\r\n 마셔도 안 됩니다. 휴게실은 모든 직원이 사용하는 곳이니까 \r\n 항상 깨끗이 사용합시다. 휴게실 사용 시간은 아침 8 시부터\r\n 저녁 9 시 까지 입니다. 9 시에 휴게실에서 나갈 때는 반드시\r\n 에어컨과 전깃불을 꺼 주십기오.', '', NULL, NULL, 'C', '청소 당번         ', '', NULL, NULL, '회사 규칙\r', '', NULL, NULL, '휴게실 규칙          ', '', NULL, NULL, '기숙사 규칙', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"under