(1482, 93, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '회사에서 상사를 부를 때는 반장님과 같이 직책에 님을 붙입니다. 친한\r\n동료나 비슷한 직급의 사람에게는 이름에 씨를 붙여서 민수 씨라고 \r\n부릅니다. 하지만 성에만 씨를 붙여 김 씨와 같이 부르면 안 됩니다. \r\n직장 밖에서는 친한 사람들끼리는 형, 누나와 같은 호칭을 사용하기도 \r\n합니다.', '', NULL, NULL, 'A', ' 지급이 비슷하면 이름에 씨를 붙여 부릅니다.\r', '', NULL, NULL, '친한 사람끼리는 형, 누나라고 부르지 않습니다.\r', '', NULL, NULL, ' 동료인 김민수 씨에게는 김 씨라고 부르면 됩니다.\r', '', NULL, NULL, '김민수 과장이 상사이면 김민수 과장이라고 부릅니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": fals