(1522, 94, '다음 글을 읽고 내용과 맞는 것을 고르십시오.', '마두 씨는 어제 저녁에 친구들과 같이 맥주를 마시고 배탈이 났습니다. \r\n시간이 늦어서 병원에 가지고 못하고 밤새 앓았습니다. 아마 저녁을\r\n먹지 않고 빈속에 맥주를 먹어서 배탈이 난 것 같습니다. 설사를 많이\r\n해서 몸에 기운이 하나도 없습니다. 힘들지만 아침에 일어나서 공장에 \r\n일하러 나갔습니다. 하루 종일 너무 힘들었습니다. 다음 부터는 절대로 \r\n빈속에 술을 마시지 않기로 했습니다.', '', NULL, NULL, 'B', '마두 씨는 병원에 갔습니다.', '', NULL, NULL, '마두 씨는 오늘 출근 해서 일했습니다.\r', '', NULL, NULL, '마두씨는 술 때문에 오늘 많이 기쁩니다.\r', '', NULL, NULL, '마두 씨는 앞으로 술을 마시지 않겠습니다.	', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bo