(1557, 95, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.\r\n', '친구하고 만나기로 약속을 했는데 삼십 분이나 늦었습니다.\r\n내가 약속 시간을 못__________친구는 화사 많이 났습니다.', '', NULL, NULL, 'C', '정해서            ', '', NULL, NULL, '정해야             ', '', NULL, NULL, '지켜서                 ', '', NULL, NULL, '지켜야', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1558, 95, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.\r\n', '어제 운동화를 샀습니다.________비싸서 사지 않으려고 \r\n  했는데 오천원을 깎아 주셔서 샀습니다.', '', NULL, NULL, 'A', '좀           ', '', NULL, NULL, '미리         ', '', NULL, NULL, '별로           ', '', NULL, NULL, '벌써', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1559, 95, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.\r\n', '국제 전화 카드를_____________요금이 쌉니다. 심야 시간이나 \r\n공휴일 등의 할인 시간대에는 요금을 더 아낄 수 있습니다.', '', NULL, NULL, 'B', '고르면                                                ', '', NULL, NULL, '사용하면', '', NULL, NULL, ' 고르면서                                             ', '', NULL, NULL, '사용하면서', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1560, 95, '다음 설명에 알맞은 어휘를 고르십시오.', '비닐로 덮어 만든 간이 온실로, 농작물을 재배하기 위해 사용된다.\r\n비닐하우스에서는 온도를 조절할 수 있어 겨울에도 채소를 키울 \r\n수 있다.', '', NULL, NULL, 'D', '전리 방사선  ', '', NULL, NULL, '오염 환경       ', '', NULL, NULL, '소음성 난청       ', '', NULL, NULL, '비닐하우스', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1561, 95, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '한국 돈을 동전과 지폐로 이루어져 있습니다. 동전은 여섯 \r\n가지인데 일상생활에서는 십 원, 백 원, 이렇게 네 가지 동전\r\n을 많이 사용합니다. 동전에는 대가 식물이나 동물, 문화재가 \r\n그려져 있는데 백 원짜리 동전에는 사람인 이순신 장군이 \r\n생겨져 있습니다. 지폐는 원래 천 원, 오천 원, 만 원만 있어\r\n는데 2009년부터 오만 원권이 나오면서 네 종류가 되었습\r\n니다. 지폐에는 모두 역사적으로 유명한 인물이 그려져 있는\r\n데 오만 원권의 신사임당을 빼고는 다 남자입니다.', '', NULL, NULL, 'C', ' 한국의 인물                                 ', '', NULL, NULL, '한국의 문화재\r', '', NULL, NULL, '한국의 화폐              ', '', NULL, NULL, '한국의 동식물', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, 