(1562, 95, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '한국은 과거 원조를 받던 나라에서 이제는 원조를 하는 나라가 되었습니다. 아프리카와 아시아의 저개발 국가에 경제적으로 원조를 하고 의료, 기술, 교육 등 많은 지원을 하고 있습니다. 또한 한국은 생활 환경이 편리하고 치안이 안전되어 많은 외국인들이 살고 싶어하는 나라가 되었습니다.', '', NULL, NULL, 'D', '한국은 치안이 안 좋아서 조금 위험입니다.\r', '', NULL, NULL, '한국은 지금 원조를 받는 나라가 되었습니다.\r', '', NULL, NULL, '한국은 외국에서 살고 싶어하는 사람들이 거의 없습니다.', '', NULL, NULL, ' 한국은 도움이 필요한 다른 나라를 도와주고 있습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": f