(1640, 97, '다음 설명에 알맞은 어휘를 고르십시오.', '근로자가 실직했을 때 생계를 보호하고 재취업을 지원하기 위해 \r\n정부가 운영하는 사회보험 제도입니다. 이는 실업급여 지급뿐만 \r\n아니라 직업훈련 및 고용안정을 위한 다양한 지원 프로그램을\r\n포함합니다.', '', NULL, NULL, 'A', '고용 보험  ', '', NULL, NULL, '산재 보험         ', '', NULL, NULL, '간강 보험', '', NULL, NULL, '최저 임금', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]'),
(1641, 97, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '한국의 명절에는 가족이나 이옷들이 함께 여러 가지 놀이도 하고 음식도 먹으면서 정을 나눕니다. 명절에 먹는 음식에는 모두좋은 의미가 있습니다. 설날에는 떡국을 먹는데 여기에는 장수의\r\n의미가 있습니다. 정월대보름에는 풍요를 기원하면서 다섯 가지 곡식을 섞어 오국밥을 지어 먹고, 1 년 내내 건강하기를바라면서 부럼과 귀밝이술을 먹습니다. 추석에는수확이 끝난 쌀햅쌀밥을 짓고 송편을 만들어 먹습니다. 이는 추석을 축하하고 소원이 이루어지기를 바라는 의미입니다.', '', NULL, NULL, 'B', '멸절 행사의 종류   ', '', NULL, NULL, '명절 음식의 의미\r', '', NULL, NULL, ' 명절 음식 만드는 법                            ', '', NULL, NULL, '멸절에 줄기는 놀이', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\