(1643, 97, '다다음 글을 읽고 내용과 맞는 것을 고르십시오.', '저는 과수원에서 일하다가 두 달 전부터 공장에서 일하고 있습니다. 가구를 \r\n조립하는 일은 힘들지만 재미있습니다. 여기는 과수원과 달리 야간 근무도 \r\n가끔 합니다. 이번 주는 주문이 많아서 일요일에도 일해야 합니다. 일이 \r\n많으면 힘들지만 수당을 더 받을 수 있어서 좋습니다.', '', NULL, NULL, 'D', '이 사람은 매주 일요일에 근무를 합니다.\r', '', NULL, NULL, '이 사람은 과수원에서 밤에도 일했습니다.\r', '', NULL, NULL, '이 사람은 가구 공장이 첫 번째 사업장입니다.\r', '', NULL, NULL, '이 사람은 가구 공장에서 일한 지 두 달 돠었숩나다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": fa