(1679, 98, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '자동판매기에서 물건을 살 때는 먼저 돈을 넣고 선택한 \r\n물건의 버튼을 누릅니다. 그 다음에 물건과 거스름돈을_\r\n___________됩니다.', '', NULL, NULL, 'B', ' 정하면', '', NULL, NULL, '꺼내면           ', '', NULL, NULL, '놓으면           ', '', NULL, NULL, '나누면', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1680, 98, '다음 설명에 알맞은 어휘를 고르십시오.', '양손을 깍지를 껴서 머리 뒤를 잡고 상체를 숙이지 않고 머리를\r\n당기는 운동입니다.', '', NULL, NULL, 'B', '팔 운동           ', '', NULL, NULL, '목 운동          ', '', NULL, NULL, '어깨 운동', '', NULL, NULL, '허벅지 운동', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]'),
(1681, 98, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '세계적으로 이기를 얻고 있는 한국의 대중문화를 한류라고 \r\n합니다. 처음에는 중국과 동남아를 중심으로 드라마나 가요가\r\n 인기를 얻었으니까 최근에는  유럽과 만아메리카까지 한류의 \r\n바람이 불고 있습니다. 그리고 한류는 드라마나 노래뿐만 \r\n아니라 음식과 다른 상품에도 확대되고 있습니다. 한국의\r\n 김치나 비빔밥 그리고 전자제품 등은 세계인들의 관심을 받고\r\n있습니다. 이러한 영향을 방문하는 관광객과 한국어를 배우려는\r\n 외국인들이 늘고 있습니다.', '', NULL, NULL, 'A', ' 한류의 인기 ', '', NULL, NULL, '한류의 시작', '', NULL, NULL, ' 한류의 이유', '', NULL, NULL, '한류의 문제점', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underl