(1682, 98, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '모서리를 다듬할 때는 줄을 이용하는 것보다 그라인더를 사용 하면 일도 빨리 할 수 있고 편리합니다. 그라인더를 사용할 때는 파편이 퇼 수 있으니까 꼭 보안겨을 쓰고 작업을 해야 합니다. 그리고 작업을 시작하기 전에 그라인더에 숫돌을 꼭 확인해서 사용해야 합니다.', '', NULL, NULL, 'C', '그라인더 작업을 보안경 없이 하면 더 안전한다.', '', NULL, NULL, '그라인더 작업한 후에 꼭 숫돌을 확인해야 한다.', '', NULL, NULL, '안전한 작업 진행을 하기 위해 보안경을 써야 한다.\r', '', NULL, NULL, '모서리를 다담할 때는 그라인더보다 줄이 빨른다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underl