(1718, 99, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '인터넷 전화는  싸고 편리합니다. 특히 외국으로 전화를 걸 \r\n때 이용하면 일발 전화보다______싸게 이용할 수 있습니다.', '', NULL, NULL, 'A', '훨씬                                                ', '', NULL, NULL, '먼저', '', NULL, NULL, ' 잠깐                                                ', '', NULL, NULL, '다시', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1719, 99, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '저는 회사에서 계속 일하고 싶습니다. 그래서 근로 계약이\r\n 끝나면 계약을____________합니다.', '', NULL, NULL, 'D', '해지하려고                               ', '', NULL, NULL, '만료하려고\r', '', NULL, NULL, ' 취소하려고                               ', '', NULL, NULL, '연장하려고', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1720, 99, '다음 설명에 알맞은 어휘를 고르십시오.', '한국에는 결혼식이 끝나고 나서 신랑 부모님과 친척들게 드리는 \r\n대표적인 인사입니다.', '', NULL, NULL, 'C', '결혼', '', NULL, NULL, '맞선              ', '', NULL, NULL, '폐백  ', '', NULL, NULL, '상견례', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1721, 99, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '새집으로 이사한 사람들이 친구나 친척들을 집으로 초대해서 여\r\n는 파티를 집들이라고 합니다. 집들이에서는 집주인이 음식을 \r\n준비해서 집을 방문한 사람들에게 대접합니다. 초대를 받은 사\r\n람들은 이사를 축하하기 위해 가루비누나 두루마리 화장지 같은\r\n선물을 사 갑니다. 이 선물들에는 특별한 의미가 있습니다. 가루\r\n비누 선물은 비누에서 나오는 거품처럼 돈을 많이 벌어서 부자\r\n가 되라는 의미를 담고 있습니다. 또 두루마리 화장지는 술술잘 \r\n풀리는 화장지처럼 모든 일이 잘 되라는 뜻으로 선물합니다.', '', NULL, NULL, 'A', '집들이 선물                                   ', '', NULL, NULL, '집들이 음식\r', '', NULL, NULL, ' 집들이 시간                                   ', '', NULL, NULL, ' 집들이 인사', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\"