(1762, 100, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '최근에는 키오스크를 이용해 음식을 주문하는 가게가 많아지고 있습니다. 키오스크를 사용하면 메뉴 선택과 결제를 한 번에 할 수 있어서 매우 편리합니다. 터치스크린을 통해 원하는 메뉴와 개수를 고르고, 카드나 모바일 결제 시스템을 이용해 결제하면 됩니다. 키오스크 덕분에 사람들은 음식을 빠르고 간편하게 주문할 수 있습니다.', '', NULL, NULL, 'C', '주문할 메뉴를 직원에게 말해야 한다.', '', NULL, NULL, ' 현금으로만 결제가 가능하다.\r', '', NULL, NULL, '주문과 결제를 한 번에 할 수 있다. ', '', NULL, NULL, '전화로만 주문이 가능하다.INSERT INTO `questions` (`id`, `quiz_set_id`, `question`, `optional_text`, `question_file`, `question_file_type`, `question_file_mime`, `correct_answer`, `choice_A_text`, `choice_A_file`, `choice_A_file_type`, `choice_A_file_mime`, `choice_B_text`, `choice_B_file`, `choice_B_file_type`, `choice_B_file_mime`, `choice_C_text`, `choice_C_file`, `choice_C_file_type`, `choice_C_file_mime`, `choice_D_text`, `choice_D_file`, `choice_D_file_type`, `choice_D_file_mime`, `question_type`, `question_word_formatting`, `optional_word_formatting`, `choice_A_word_formatting`, `choice_B_word_formatting`, `choice_C_word_formatting`, `choice_D_word_formatting`) VALUES
