(1857, 102, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '전선을 자를 때는 니퍼를 씁니다. 그리고 철사를 자를 때도 ________것이 \r\n 좋습니다.', '', NULL, NULL, 'D', '끓는             ', '', NULL, NULL, '자르는 ', '', NULL, NULL, '구부리는           ', '', NULL, NULL, '사용하는', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1858, 102, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '8월 15일에 한국어능력시험이 있습니다. 시험을 신청하실\r\n 분들은 6월 30일까지 사무실에 직접 오셔서 응시 원서를\r\n __________합니다.', '', NULL, NULL, 'C', '보관해야                                                     ', '', NULL, NULL, ' 보관할까\r', '', NULL, NULL, ' 접수해야                                                    ', '', NULL, NULL, '접수할까', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1859, 102, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '겨울 잠바를 사러 백화점에 갔는데 옷이__________\r\n  비쌉습니다. 그래서 내일 시장에 한번 가 보려고 합니다..', '', NULL, NULL, 'D', '아까  ', '', NULL, NULL, ' 혹시\r', '', NULL, NULL, '별로                                                ', '', NULL, NULL, '너무', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1860, 102, '빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '매주 일요일마다 회사 동료와 같이 산에 갑니다. 산에 오를 \r\n때는 힘들지만 정상에___________기분이 참 좋아집니다.', '', NULL, NULL, 'B', '도착하고    ', '', NULL, NULL, '도착하면', '', NULL, NULL, '내려오고                                       ', '', NULL, NULL, '내려오면', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1861, 102, '다음 설명에 알맞은 어휘를 고르십시오.', '응급 환자가 생겼을 때나 건단한 다칠 때 쓸 수 있도록 약을 \r\n정리해 두는 상자입니다', '', NULL, NULL, 'A', '구급함                                                 ', '', NULL, NULL, '공구함', '', NULL, NULL, ' 컨테이너                                              ', '', NULL, NULL, '보관함', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(1862, 102, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '외국인 근로자 전용 4 대 보험에는 출국만기보험, 귀국 비용\r\n보험, 보증보험, 상해보험이 있습니다. 이 중에서 상해 보험과 \r\n귀국비용 보험은 외국인 근로자가 반드시 가입해야 하는 보험\r\n입니다. 출국만기 보험, 귀국미용보험, 상해보험을 받으려면 \r\n삼성화재에 팩스로 신청을 하면 됩니다. 보증 보험은 서울보증\r\n보험회사에 신청 해야 받을 수 있습니다.', '', NULL, NULL, 'A', '보험과 조건                                                                                 ', '', NULL, NULL, '보험과 지급 날\r', '', NULL, NULL, '보험과 지급 방법                         ', '', NULL, NULL, ' 한국인이 뽑은 여행지', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\"