(1863, 102, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '서울역 공항터미널이 문을 열었습니다. 이제 무거운 가방을 들고 인천 공항까지 가지 않으셔도 됩니다. 서울역에서 짐을 부치고 바로 공항에 가서 비행기를 타실 수 있습니다. 공항버스로 40 분이면 도착합니다. 해외여행을 떠나실 분들은 서울역 공항터미널로 오시가 바랍니다..', '', NULL, NULL, 'D', '공항에 가기 전에 짐을 보낼 수 없습니다.\r', '', NULL, NULL, ' 공항 터미널은 국내여행을 할 때 더 좋습니다.\r', '', NULL, NULL, '서울역 공항터미널은 오래 전에 만들었습니다.\r', '', NULL, NULL, ' 서울역에서 공항에 가려면 공항버스를 타야 합니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"un