(1864, 102, '다음 글을 읽고 내용과 같은 것을 고르십시오.\r\n', '우체국에서는 외국인 근로자, 유학생, 결혼이민자 등 외국인 3,000\r\n 여 명을 대상으로 고향에 편지 보내기 행사를 열었습니다. 이번 \r\n 행사는 국제항공 우편 엽서는 5,000 원으로 전 세계에 보낼 수 있\r\n 는 엽서입니다. 참가자들은 고향에 있는 가족과 친구들에게 사랑하\r\n 는 마음을 써서 보냈습니다.', '', NULL, NULL, 'C', ' 5000 원으로 전 세계에 엽서를 보낼 수 없습니다.\r', '', NULL, NULL, ' 참가자는 각자 자기 나라로만 편지를 보낼 수 있습니다.\r', '', NULL, NULL, ' 외국인 3,000 명 정도가 참석하였습니다.\r', '', NULL, NULL, '참가자들은 고향에 있는 가족들에게 편지를 안썼습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": fal