(1905, 103, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '불이 나면 소화기를 들고 바람이 부는 방향에서 불에 접근하세요. 앞\r\n쪽에 불부터 소화하고 위에서 아래로 뿜어애야 합니다. 되도록 충분히\r\n많이 소화기를 한번에 사용하고 불을 꺼야 합니다. 마지막으로 불씨가\r\n남아 있는지 확인하고 사용한 소화기를 다시 층전해야 합니다.', '', NULL, NULL, 'A', '불을 끄는 방법', '', NULL, NULL, '불을 옮기는 방법', '', NULL, NULL, '불에서 주의점', '', NULL, NULL, '불의 위험성', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bol