(1906, 103, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '한국의 결혼 식에서는 서양식 결혼식과  전통 혼례의 풍습을 모두 불 수 있습니다. 웨딩드레스를 입고 하는 서양식 결혼식이 끝나면 신랑, 신부는 정통 방식으로 신랑의 부모님과 친척들에게 인사를 드립니다. 이것을 폐백이라고 하는데 이따신랑, 신부는 한복으로 갈아 입고 어른들에게 큰절을 올립니다.', '', NULL, NULL, 'D', '폐배은 서양식 결혼식 풍습니다.\r', '', NULL, NULL, '폐백은 결혼식을 시작하기 전에 합니다.\r', '', NULL, NULL, '폐백은 신부는 웨딩드레스를 입습니다.\r', '', NULL, NULL, '폐백은 시랑 가족들에게 하는 인사입니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\