(1907, 103, '다음 글을 읽고 같은 것을 고르십시오.', '우리 집 고양이 이름은 미미입니다. 6개월 전에 제가 퇴근해서 집에 돌아올 때 길에서 \r\n만났습니다. 그때 미미는 다리를 다쳐서 힘들어 보였습니다. 그리고 배도 고픈 것 같았\r\n습니다. 저는 미미를 집으로 데려와서 밥을 주고 약도 발라 주었습니다. 처음에 미미는 \r\n저한테 가끼이 오지 않았습니다. 하지만 이제는 저와 있는 것을 좋아합니다.', '', NULL, NULL, 'A', '저는 다친 고양이를 도와주었습니다.\r', '', NULL, NULL, '저는여섯 달 전에 고양이를 샀습니다.', '', NULL, NULL, '저는 길에서 고양이를 잃어버렸습니다.\r', '', NULL, NULL, '저는 처음부터 고양이와 친하게 지냈습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {