(1953, 104, '다음 글을 읽고 내용과 맞는 것을 고르십시오..', '방사선은 눈에 보이지 않지만 오랜 시간 동안 계속해서 노출되면 병에 걸릴 수있습니다. 그러므로 방사선 작업은되도록 짧게 하고 가능하면 멀리 떨어 져서 해야 합니다. 또한 작업 전에는 방사선을 막을 수 있는 보호구를 반드시착용해야 합니다.', '', NULL, NULL, 'C', '방사선은 눈으로 불 수 있습니다.\r', '', NULL, NULL, '방사선을 막을 수 있는 보호구는 없습니다.\r', '', NULL, NULL, '방사선 작업은 가능한 한 먼 곳에서 해야 합니다.\r', '', NULL, NULL, '방사선 작업을 오래 해도 건강에는 문제가 없습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"