(1995, 105, '다음 글을 읽고 같은 것을 고르십시오.', '집들이 선물로는 휴지나 세제가 인기가 있습니다. 이런 선물에는 좋은 일이 많이 생기\r\n고 부자가 되라는 의미가 담겨 있습니다. 하지만 요즘에는 집주인에게 필요한 선물을 \r\n사 주기도 합니다. 커피 잔처럼 부부가 같이 쓸 수 있는 물건이나 시계, 화문 같은 장식\r\n용품도 인기가 많습니다.', '', NULL, NULL, 'D', '요즘에는 휴지 선물을 하지 않습니다.', '', NULL, NULL, '집들이 때 시계를 선물하면 안 됩니다.\r', '', NULL, NULL, '세제 선물에는 깨끗해지라는 의미가 있습니다.\r', '', NULL, NULL, ' 부부각 같이 쓸 수 있는 선물이 인기가 있습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"