(2078, 107, '다음 글을 읽고 같은 것을 고르십시오.', '라스트 씨는 최근 집 근처에 생긴 무인 판매점을 이용해 보았습니다. 밤늦은 시간에도 \r\n필요한 음식이나 음료를 편리하게 살 수 있어서 매우 만족했습니다. 다양한 언어가 제\r\n공되어 외국인들도 무인 판매점을 쉽게 이용할 수 있다는 것을 알게 되었습니다.', '', NULL, NULL, 'C', '라스트 씨는 외국어로 물건을 팔았습니다.', '', NULL, NULL, '무인 판매점은 낮 시간에만 이용할 수 있습니다.', '', NULL, NULL, '무인 판매점은 다양한 언어를 지원합니다.\r', '', NULL, NULL, '라스트 씨는 무인 판매점에서 일하고 있습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {