(2160, 109, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '발이 편하면 몸도 편합니다. 발을 편하게 하려면 어떻게 해야 할까요? 굽이 낮은 구두\r\n나 운동화를 신으십시오. 걸을 때에는 천천히 걷는 것보다 빠른 걸음으로 걷는 것이 \r\n좋습니다. 급 신발을 벗고 걷는 것도 좋습니다. 저녁에 발이 피곤하다면 발을 조금 높\r\n은 곳에 두고 주무십시오.', '', NULL, NULL, 'B', '천천히 걸으면 발이 편합니다.', '', NULL, NULL, '신발을 벗고 걷는 것이 좋습니다.', '', NULL, NULL, '구두를 신으면 발이 피곤해집니다.', '', NULL, NULL, '팔을 높게 하고 자면 발이 편해집니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false},