(2198, 110, '다음 설명에 알맞은 어휘를 고르십시오.', '높은 곳에서 일할 때는 추락(아래로 떨어짐)의 위험이 있습니다. 그로므로 몸을 보호\r\n하는 보호구를 반드시 착용해야 합니다.', '', NULL, NULL, 'C', '안전모', '', NULL, NULL, '안전복', '', NULL, NULL, '안전대', '', NULL, NULL, '안전화', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(2199, 110, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '저하고 같이 일하는 투안 씨는 참 부지런한 사람입니다. 아침에 일찍 \r\n일어나서 운동도 하고 청소도 합니다.', '', NULL, NULL, 'A', '동료 소개', '', NULL, NULL, '업무 소개', '', NULL, NULL, '근무 조건', '', NULL, NULL, '근무 장소', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]'),
(2200, 110, '다음 글을 읽고 내용과 다른 것을 고르십시오.', '한국에서는 이사를 한 후에 집들이를 합니다. 집들이는 가까운 사람들을 새집에 초대해서 음식을 대접하는 것입니다. 집들이에 초대 받은 사람은 보통 세제나 비누, 휴지 등을 선물합니다. 이런 선물들에는 좋은 일이 많이 생기고 어려운 일이 잘 해결되기를 바라는 의미가 담겨 있습니다.', '', NULL, NULL, 'C', '주인은 손님에게 세제나 비누를 줍니다.', '', NULL, NULL, '보통 이사를 가기 전에 집들이를 합니다.\r', '', NULL, NULL, '집들이 선물에는 좋은 의미가 담겨 있습니다.', '', NULL, NULL, '집들이에 초대 받은 사람은 음식을 준비해 갑니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underlin