(2201, 110, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '한국에서는 식사할 때 식탁 위에 밥과 국, 반찬을 한께번에 차려 놓고 먹습니다. 밥과 \r\n국은 한 사람이 한 그릇씩 먹으면 되고 반찬이나 찌개 같은 음식은 다른 사람들과 \r\n나누어 먹습니다. 식탁 위에서 고기를 구워 먹거나 찌개를 끓여 먹을 때는 각자의 \r\n접시에 조금씩 덜어서 먹으면 됩니다.', '', NULL, NULL, 'C', '고기는 자기 접세에만 덜어서 먹습니다.\r', '', NULL, NULL, '반찬은 한 사람이 한 가지씩 먹습니다.', '', NULL, NULL, '반찬은 다른 사람과 나누어 먹습니다.\r', '', NULL, NULL, '식탁 위에서는 째개를 끓이지 않습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"un