(2241, 111, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '불이나면 우선 다른 사람에게 큰 소리로 알려야 하고 비상벨을 누르거나 119 에 신고  \r\n합니다. 전기를 차단하고 가스 밸브를 잠급니다. 그리고 대피할 때는 낮은 자세로 움직\r\n이고 엘리베이터를 타지 말고 계단을 이용하는 것이 좋습니다. 왜냐하면 엘리베이터는\r\n멈출 수 있기 때문에 위험합니다.', '', NULL, NULL, 'C', '불이 나면 엘리베이터를 타고 빨리 내려가는 것이 좋습니다.\r', '', NULL, NULL, '불이 나면 먼저 짐을 챙기고 대피해야 합니다.	\r', '', NULL, NULL, '불이 나면 다른 사람에게 알리고 119에 신고해야 합니다.\r', '', NULL, NULL, '불이 나면 창문을 열고 바람을 통하게 해야 합니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"under