(2321, 113, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '그동안 저희 식당을 잊지 않고 기다려 주신 손님 여러분께 감사 드립니다. 이번 9월에 다시 문을 연 저희 식당은 훨씬 넓은  곳에서 더 많은 메뉴로 여러분을 만나려고 합니다. 부모님과 아이들이 편하게 드실 수 있는 방도 새로 만들었습니다. 또한 9월 한 달 동안 음식 값을 20% 할인해 드립니다. 많이 이용해 주십시오.', '', NULL, NULL, 'B', '이 식당은 팔월에 쉬지 않았습니다.\r', '', NULL, NULL, ' 이 식당은 전보다 많이 커졌습니다.\r', '', NULL, NULL, '부모님과 함께 오면 할인해 드립니다.\r', '', NULL, NULL, '이 식당에는 가족을 의한 방이 없습니다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": fa