(2322, 113, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '백화점에서 세일을 할 때는 손님들에게 빠른 음악을 들려줍니다. 그러면 손님들이\r\n 빨리 많은 물건을 사기 때문입니다. 그러나 세일을 안 할 때는 조용하고 가벼운\r\n 음악을 들려줍니다. 그런 음악은 손님들이 천천히 구경 하면서 오랫동안 쇼핑을 \r\n 하게 만듭니다.', '', NULL, NULL, 'A', '세일할 때는 빠른 음악이 나옵니다.', '', NULL, NULL, '세일할 때는 손님들이 오래 쇼핑을 합니다.', '', NULL, NULL, '가벼운 음악으로 물건을 많이 팔 수 있습니다.', '', NULL, NULL, '물건을 많이 사는 손님들은 조용한 음악을 좋아합니다.\r', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": true}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\