(2354, 166, '나이가 많은 사람에게 악수할 때 올바른 예절은 무엇입니까?', '“안녕하세요?”, “안녕하십니까?”, “안녕?”은 인사하는 시간에\r\n 상 관없이 아침, 점심, 저녁 언제든지 사용할 수 있습니다.\r\n공적인 상황에서는 주로 악수를 하며 인사합니다. 다만, \r\n자신보 다 나이가 훨씬 많거나 지위가 높은 사람에게 \r\n인사할 때는 왼손으로 오른팔이나 오른손을 받치고 \r\n악수를 하는 것이 예의입니다.', '', NULL, NULL, 'D', '왼손을 주머니에 넣고 악수한다.\r', '', NULL, NULL, '두 손으로 상대 손을 감싼다.', '', NULL, NULL, '오른손만 사용해서 악수한다.', '', NULL, NULL, '오른손을 왼손으로 받쳐 악수한다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": 