(2362, 166, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '외국인 근로자 다라 씨는 점심시간에 구내식당을 자주 이용합니다. \r\n 식권은 미리 구입해야 하며, 입구에서 직원에게 제출합니다. 식사는\r\n 자율 배식으로 이루어지며, 먹은 후에는 식판을 정리대에 반납해야\r\n 합니다. 다라 씨는 한국 음식을 맛볼 수 있어서 구내식당 이용이 매우 \r\n 만족스럽다고 말합니다.', '', NULL, NULL, 'D', '때와 장소에 맞는 옷차림    ', '', NULL, NULL, '구내식당의 가격', '', NULL, NULL, '구내식당의 메뉴 종류', '', NULL, NULL, '구내식당의 이용 방법', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": f