(2560, 171, ' 빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '요즘 공장에서 생산량이 늘어서 일하는 시간이 길어졌습니다.INSERT INTO `questions` (`id`, `quiz_set_id`, `question`, `optional_text`, `question_file`, `question_file_type`, `question_file_mime`, `correct_answer`, `choice_A_text`, `choice_A_file`, `choice_A_file_type`, `choice_A_file_mime`, `choice_B_text`, `choice_B_file`, `choice_B_file_type`, `choice_B_file_mime`, `choice_C_text`, `choice_C_file`, `choice_C_file_type`, `choice_C_file_mime`, `choice_D_text`, `choice_D_file`, `choice_D_file_type`, `choice_D_file_mime`, `question_type`, `question_word_formatting`, `optional_word_formatting`, `choice_A_word_formatting`, `choice_B_word_formatting`, `choice_C_word_formatting`, `choice_D_word_formatting`) VALUES
(2595, 172, '다음 글의 내용과 맞는 것을 고르십시오.', '빌트인 가구는 실내 인테리어와 조화를 이루며 깔끔하고 현대적인 느낌을 주기 때문에 더욱 인기가 많아지고 있습니다. 최근에 지은 아파트에 고급스럽고 실용적인 빌트인 가구가 많이 설치되고 있는 것도 이 때문입니다. 또한, 최근에는 가구뿐만 아니라 에어컨, 전기 오븐, 식기 세척기 등의 가전제품도 빌트인으로 제공되어 더욱 편 리하고 세련된 공간을 제공하고 있습니다.', '', NULL, NULL, 'A', '빌트인 가구는 따로 설치하지 않고 이동식으로 사용하는 것이 일반적입니다.INSERT INTO `questions` (`id`, `quiz_set_id`, `question`, `optional_text`, `question_file`, `question_file_type`, `question_file_mime`, `correct_answer`, `choice_A_text`, `choice_A_file`, `choice_A_file_type`, `choice_A_file_mime`, `choice_B_text`, `choice_B_file`, `choice_B_file_type`, `choice_B_file_mime`, `choice_C_text`, `choice_C_file`, `choice_C_file_type`, `choice_C_file_mime`, `choice_D_text`, `choice_D_file`, `choice_D_file_type`, `choice_D_file_mime`, `question_type`, `question_word_formatting`, `optional_word_formatting`, `choice_A_word_formatting`, `choice_B_word_formatting`, `choice_C_word_formatting`, `choice_D_word_formatting`) VALUES
