(1815, 101, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '월급은 보통 한국에서 개설한 은행의 통장으로 바로 입금됩니다. \r\n월급은형금으로 바로 받는 것보다는 통장으로 계좌이체를 해서 받는\r\n것이 안전합니다. 월급은 한 달에 한 번 일한 것에 대한 대가를 받는 \r\n것을 말합니다. 월급은 받을 때는 기본급과 수당 공제 내역 등이 디재\r\n된 명세서를 함께 받아서 급액이 정확한지 확인하는 것이 좋습니다.', '', NULL, NULL, 'C', '최저 임금제', '', NULL, NULL, ' 월급 계산하기\r', '', NULL, NULL, '월급 받는 방법', '', NULL, NULL, '월급 보내는 방법', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bo