(2434, 168, '다음 글을 읽고 내용과 같은 것을 고르십시오.', '저는 이번 달에 새 식품 공장에 들어왔습니다.처음에는 위생복을 입는 방법도 잘 몰라서 자주 지적을 받았습니다.하지만 지금은 손 씻기와 소독을 꼼꼼히 해서 실수가 거의 없습니다.매일 아침에는 생산 라인을 청소하고 점심 이후에는 포장 작업을 합니다.가끔 기계 소리가 너무 커서 머리가 아플 때도 있지만 참고 일합니다.요즘에는 팀장님께 칭찬을 받아서 일할 때 더 힘이 납니다.', '', NULL, NULL, 'B', '화자는 이번 달에 식당에서 일하기 시작했다.', '', NULL, NULL, '화자는 이번 달에 새 식품 공장에서 일하기 시작했다.', '', NULL, NULL, '화자는 예전부터 같은 공장에서 일하고 있다.', '', NULL, NULL, '화자는 식품 공장에서 근무하다가 다른 일로 옮겼다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\