(2512, 170, ' 빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '외국인 근로자가 본인의 사정으로 고국에 다녀오려면, 먼저 사업주의 동의를 받고 __________을/를 신청해야 합니다.', '', NULL, NULL, 'B', '급여 인상', '', NULL, NULL, '재입국 허가', '', NULL, NULL, ' 체류 연장', '', NULL, NULL, '통역 지원', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]'),
(2513, 170, ' 빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '우체국에서 국제 우편을 보내려면 ___________________과/와 주소를 정확히 적어야 합니다.정보가 틀리면 배달이 안 될 수도 있어요', '', NULL, NULL, 'C', '물건', '', NULL, NULL, '영수증', '', NULL, NULL, '발신인', '', NULL, NULL, '우표', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(2514, 170, '다음 글을 읽고 내용과 맞는 것을 고르십시오.', '한국의 대도시는 도시마다 다른 특색을 지니고 있습니다. 서울은 한국의 과거와 현대가 공존하는 곳이며 밤늦게까지 쇼핑을 즐길 수 있어 여행객이 가장 많이 찾는 도시입니다. 부산은 바다가 아름답고 맛집들이 많아 인기가 많습니다. 그리고 근대사의 흔적이 남아 있는 대구는 골목길을 따라 걷는 근대골목 투어가 관광객들의 발길을 끌고 있습니다.', '', NULL, NULL, 'D', '부산은 산책로가 잘 되어 있어 걷기 여행으로 유명하다.', '', NULL, NULL, '대구에서는 쇼핑센터를 중심으로 관광이 이루어진다.', '', NULL, NULL, '서울은 과거 유산이 보존되지 않은 도시이다.', '', NULL, NULL, '대구는 근대골목 투어로 관광객들의 관심을 끌고 있다.', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"