(2522, 170, '다음 설명에 알맞은 어휘를 고르십시오.', '외국인이 비자를 연장하거나 체류 자격을 변경할 때 방문하는 곳입니다. 여권, 사진, 서류를 제출하고 순서를 기다립니다.', '', NULL, NULL, 'C', '고용노동부', '', NULL, NULL, '공장', '', NULL, NULL, '출입국관리사무소', '', NULL, NULL, '은행', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(2523, 170, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '음식을 다 먹는 것은 환경과 자원 보호에 큰 도움이 됩니다. 우리가 먹을 만큼만 덜어 먹으면 음식물 쓰레기를 줄일 수 있습니다. 남은 음식을 버리면 자원의 낭비뿐만 아니라 처리 과정에서 환경 오염도 발생합니다. 따라서 식사할 때 적당한 양을 담는 습관이 필요합니다. 음식 남기지 않기는 작은 실천이지만, 지속적으로 실천하면 큰 변화를 만들 수 있습니다. 가족과 친구에게도 이러한 습관을 알려 함께 실천하는 것이 좋습니다.', '', NULL, NULL, 'A', '음식 남기지 않기', '', NULL, NULL, '음식 많이 담다', '', NULL, NULL, '음식 버리기', '', NULL, NULL, '배달 취소하기', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": fa