(2663, 173, '다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '우리 회사에서는 매월 한 번씩 작업장 환경을 점검합니다.특히 환기 시설과 소음 장비는 근로자의 건강과 직결되기 때문에 더 꼼꼼하게 확인합니다.점검 중 문제가 발견되면 즉시 수리팀에 연락하여 조치를 취합니다.또한 근로자들이 안전하게 일할 수 있도록 보호구 사용 교육도 함께 진행합니다.이런 과정 덕분에 우리 작업장은 사고가 거의 없다고 합니다.', '', NULL, NULL, 'B', '문화 행사 준비', '', NULL, NULL, '산업 안전 관리 ', '', NULL, NULL, '외국인 근로자 상담', '', NULL, NULL, '근무 시간 기록', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": 