(2700, 174, ' 빈칸에 들어갈 가장 알맞은 것을 고르십시오.', '대형 선박을 조립하기 위해 작업자들은 무거운 철판을 옮길 때 __________ 장비를 사용합니다.', '', NULL, NULL, 'A', '호이스트', '', NULL, NULL, ' 호이스트', '', NULL, NULL, '송풍기', '', NULL, NULL, ' 분무기', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}]'),
(2701, 174, '(17~18) 다음 설명에 알맞은 어휘를 고르십시오.', '한국에는 오래된 궁궐과 사찰, 전통 마을 등이 남아 있어역사와 문화를 배울 수 있는 장소가 많습니다.특히 유네스코 세계유산으로 지정된 곳도 여러 곳 있습니다.', '', NULL, NULL, 'B', '도시 교통망', '', NULL, NULL, '한국의 문화유산', '', NULL, NULL, '산업 안전 규정', '', NULL, NULL, '현대식 공업 단지', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]'),
(2702, 174, ' 다음 설명에 알맞은 어휘를 고르십시오.', '18. 또한 상사에게 보고하고 허락을 받는 문화가 중요하며 작업장에서는 안전장비를 제대로 착용해야 합니다.', '', NULL, NULL, 'B', '작업 도구 사용법', '', NULL, NULL, '한국 직장 문화', '', NULL, NULL, '기계 작동 매뉴얼', '', NULL, NULL, '수리 비용 안내', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]'),
(2703, 174, ' 다음 글을 읽고 무엇에 대한 글인지 고르십시오.', '19. 한국의 겨울은 매우 추우므로 난방 관리가 중요합니다. 실내 온도를 적절히 유지하면 전기 요금을 절약할 수 있습니다. 창문 틈을 막으면 따뜻한 공기가 빠져나가는 것을 줄일 수 있습니다. 외출할 때는 난방을 약하게 조절하는 것이 좋습니다.', '', NULL, NULL, 'B', '한국의 여름 날씨를 설명', '', NULL, NULL, ' 난방을 효율적으로 사용하는 방법', '', NULL, NULL, '전기 사용량을 계산하는 방법', '', NULL, NULL, '집의 구조를 설명', '', NULL, NULL, 'Reading', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}]', '[{\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bold\": false, \"underline\": false}, {\"bo